import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleCardAction = (type) => {
    if (type === 'payments') {
      alert("Redirecting to our Secure Payment Policy...");
    } else if (type === 'students') {
      navigate('/services'); 
    } else if (type === 'delivery') {
      navigate('/contact');
    }
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", overflowX: 'hidden', backgroundColor: '#f8f9fa' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '60vh',
          padding: '60px 0'
        }}>
        <div className="container text-center">
          <h1 className="display-3 fw-bold mb-3" style={{ textShadow: '2px 4px 10px rgba(0,0,0,0.2)' }}>
            Freelance <span style={{ color: '#ffc107' }}>Hub Nashik</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '700px' }}>
            The ultimate marketplace for skilled students and clients looking for top-tier solutions in Nashik.
          </p>
          <div className="d-flex justify-content-center gap-3 flex-wrap">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg border-0">
              Hire Freelancers
            </Link>
            <Link to="/register" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill border-2">
              Join as Freelancer
            </Link> 
          </div>
        </div>
      </header>

      {/* 2. Top Freelancers Section */}
      <section className="py-5 bg-white">
        <div className="container">
            <div className="text-center mb-5">
                <h2 className="fw-bold display-5">Top Freelancers</h2>
                <p className="text-muted">Hire the best student talent from Nashik</p>
                <div className="mx-auto mt-2" style={{ width: '60px', height: '4px', background: '#ffc107', borderRadius: '10px' }}></div>
            </div>

            <div className="row g-4 justify-content-center">
                
                {/* Freelancer Card 1 */}
                <div className="col-md-4 col-lg-3">
                    <div className="card border-0 shadow-lg rounded-4 p-4 text-center h-100 interactive-card">
                        <div className="position-relative mb-3 d-inline-block mx-auto">
                            {/* Updated Image Link to fix "prof..." error */}
                            <img 
                              src="https://flaticon.com" 
                              className="rounded-circle border border-4 border-white shadow-sm" 
                              style={{ width: '110px', height: '110px', objectFit: 'cover' }} 
                              alt="Freelancer Profile" 
                            />
                            {/* Online Green Dot (WhatsApp Style) */}
                            <span className="position-absolute bottom-0 end-0 bg-success border border-2 border-white rounded-circle" 
                                  style={{ width: '20px', height: '20px', marginBottom: '5px', marginRight: '5px' }}></span>
                        </div>
                        <h5 className="fw-bold mb-1">Rahul Patil</h5>
                        <p className="text-primary small fw-semibold mb-3">Full Stack Developer</p>
                        <div className="d-flex justify-content-center gap-2 mb-4">
                            <span className="badge bg-light text-dark border px-2 py-1">React</span>
                            <span className="badge bg-light text-dark border px-2 py-1">Node.js</span>
                        </div>
                        <button 
                          onClick={() => navigate('/profile/1')} 
                          className="btn btn-primary w-100 rounded-pill fw-bold py-2"
                        >
                          View Profile
                        </button>
                    </div>
                </div>

            </div>
            
            <div className="text-center mt-5">
                <Link to="/services" className="text-decoration-none fw-bold text-primary">Explore All Freelancers →</Link>
            </div>
        </div>
      </section>

      {/* 3. Features Section */}
      <section className="py-5 bg-light border-top">
        <div className="container py-4 text-center">
          <div className="row g-4">
            <div className="col-md-4" onClick={() => handleCardAction('payments')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-5 mb-3 text-warning">🛡️</div>
                <h5 className="fw-bold">Secure Payments</h5>
                <p className="text-muted small">Safe escrow-based transactions for every single project.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('students')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-5 mb-3 text-primary">🎓</div>
                <h5 className="fw-bold">Verified Talent</h5>
                <p className="text-muted small">Work with top-rated talent from verified backgrounds.</p>
              </div>
            </div>
            <div className="col-md-4" onClick={() => handleCardAction('delivery')} style={{ cursor: 'pointer' }}>
              <div className="p-4 rounded-4 feature-box bg-white shadow-sm h-100">
                <div className="display-5 mb-3 text-success">⚡</div>
                <h5 className="fw-bold">Fast Delivery</h5>
                <p className="text-muted small">Optimized workflows to ensure projects are on time.</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. Nashik Location Section (Updated Map URL) */}
      <section id="contact" className="py-5 bg-white">
        <div className="container text-center">
          <h2 className="fw-bold mb-4">📍 Our Hub in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto border border-white border-4" style={{ maxWidth: '1000px', height: '400px' }}>
            <iframe
              title="Nashik Map"
              src="https://google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <style>{`
        .interactive-card { 
          transition: all 0.3s ease-in-out; 
        }
        .interactive-card:hover { 
          transform: translateY(-10px); 
          box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important; 
        }
        .feature-box:hover {
          background: #fdfdfd;
          transform: translateY(-5px);
          transition: 0.3s;
        }
        .btn-primary { 
          background: #1e3c72; 
          border: none;
        }
        .btn-primary:hover { 
          background: #2a5298; 
        }
      `}</style>

    </div>
  );
}

export default Home;
